var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"술래 많은 술래잡기라니. 크레데레도 힘들겠다.","JPN":"鬼が大量にいる鬼ごっこなんて、さすがのクレデレでもしんどいだろうね。","ENG":"Playing tag while multiple tags are chasing Credere must be difficult.","TWN":"和這麼多人玩捉迷藏。克蕾妲莉也會很辛苦吧。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"술래한테 잡히면 벌칙도 여러 명에게 받아야 하잖아.","JPN":"鬼に捕まったら、鬼が多い分、罰も倍なんでしょ？","ENG":"What happens if you get tagged by multiple people at the same time?","TWN":"被那麼多人捉到的話，懲罰該怎麼算呢……"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"세상이 멸망해도 살아남을 것 같은 녀석이잖아요. 너무 걱정하지 마세요.","JPN":"まぁ、あの子は世界が滅ぼうとも、生き残っていけそうですし、あまり心配はいらないと思いますが。","ENG":"She's the type to survive the apocalypse, though. I wouldn't worry too much about her.","TWN":"別太擔心。就算世界毀滅了，那傢伙也能活下來。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이건 팀전이니까 저희는 보물을 찾는 데에만 집중하자고요.","JPN":"これは協力プレイですから、私たちはまず宝探しに集中しましょう。","ENG":"This is a team fight, so let's focus on finding the treasure.","TWN":"這是團隊賽，所以我們先專心尋寶吧？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응! 엄청 빨리 찾아서 크레데레를 깜짝 놀라게 해주자!","JPN":"うん！　とんでもないスピードで見つけ出して、クレデレを驚かせちゃおう！","ENG":"Yeah! Let's find it quickly and surprise Credere!","TWN":"嗯！我們要很快找到寶物，讓克蕾妲莉大吃一驚！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 그럼 일단은-","JPN":"はい、じゃあまずは－","ENG":"Right. First–","TWN":"好。那麼先——"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"정답. 순순히 잡혀간다.","JPN":"正解。大人しく捕まりましょうね。","ENG":"Surrender and follow us.","TWN":"沒錯。乖乖束手就擒吧。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그쪽이 서로 편하고 좋지 않겠어요?","JPN":"その方が、お互いのためでしょう？","ENG":"That would be convenient and cause less trouble for both of us.","TWN":"這樣我們雙方都省事，不是很好嗎？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"꺄아아아악!?","JPN":"きゃあああっ！？","ENG":"Kyaaah?!","TWN":"呀啊啊阿！！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"움직이지 마세요. 비살상용이긴 해도 직접 맞으면 꽤나 따끔하니까.","JPN":"動かないでください。非致死性ですが、当たると結構痛いんですよ。","ENG":"Stay still. This may be a non-lethal, but it'll still hurt if you get shot by it.","TWN":"別動。雖然是空包彈，但直接打中還是會很痛的。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아-아! 반칙! 갑자기 끼어드는 건 반칙이야!","JPN":"もうっ！　こんなの反則だよ！　横から急に入ってくるのはなしでしょ！","ENG":"Hey! You're cheating! You can't just cut in the middle!","TWN":"啊！犯規！突然插隊是犯規的！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물찾기에서 무기 사용은 안된다구, 알트 소대장 언니!","JPN":"宝探しにおいて、武器の使用は禁止だよ。アルト小隊のお姉ちゃん！","ENG":"No weapons are allowed in a treasure hunt, ALT Commander!","TWN":"尋寶時不能使用武器，阿爾特小隊長姊姊！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"맞출 생각은 없으니까 안심하세요.","JPN":"当てるつもりはないですから、ご安心を。","ENG":"Don't worry. We have no intentions of hitting you.","TWN":"放心，我根本沒想瞄準。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네. 물론 저항한다면 피차 피곤해지겠지만.","JPN":"でも抵抗されるとなると、少し話は変わります。","ENG":"That's right. If you resist, however, it will make things that much harder.","TWN":"當然，如果你們反抗的話，大家都會很累。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"매, 매뉴얼에서 봤어요. 당신들은 알트 소대죠?","JPN":"ま、マニュアルで見ました。あなたたち、アルト小隊ですよね？","ENG":"I-I saw you in the manual. You're ALT Squad, right?","TWN":"我、我在手冊上看到過。你們是阿爾特小隊，對吧？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"타이탄 씨도 그랬지만, 대체 부사장님한테 무슨 소리를 들으신 거예요?","JPN":"タイタンさんの時もですが、いったい副社長に何を聞かされているんですか？","ENG":"It happened earlier with Titan, but what on earth did the Vice President tell you?","TWN":"泰坦先生也是這樣，副總到底和你們說了什麼？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"얘기라면 돌아가면서 천천히 나눠보죠. 그쪽을 데려가는 게 저희 임무거든요.","JPN":"その話なら、歩きながらしましょう。私たちはあなたたちを連行しにきているので。","ENG":"If you wish to talk, we can talk on the way back. It is our mission to take you back.","TWN":"如果是要談話的話，我們可以回去路上慢慢聊。我的任務只是帶你們回去。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"놀이는 끝이에요. 실장님도 그만 돌아오세요.","JPN":"もうお遊びはおしまいです。室長ももう戻ってきてください。","ENG":"Playtime's over. You need to come back too, Chief.","TWN":"遊戲結束了。室長，你也該回來了。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"싫~어. 아직 보물을 못 찾았단 말이야.","JPN":"や～だ～！　まだ宝探しの途中なんだもん。","ENG":"Noooo. I haven't found the treasure yet.","TWN":"不～～要。我們還沒找到寶藏呢。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"하아… 실장님. 그건 평범한 보물이 아니라 아티팩트예요.","JPN":"はぁ……室長。これは普通のお宝ではなく、アーティファクトのようです。","ENG":"*Sigh* Chief. That's not an ordinary treasure. It's an Artifact.","TWN":"哀……室長，那個不是普通的寶物，而是人造神器。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"뭣 모르고 열었다가 큰일이라도 나면 어쩌려고 그래요?","JPN":"無闇に開けると、大変なことになるかもしれませんよ？","ENG":"You don't know what might happen upon opening it.","TWN":"你不知道就隨便打開，要是出了什麼大事該怎麼辦？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아티팩트…? 당신 보물에 대해 알고 있는 건가요?","JPN":"アーティファクト……？　あなた、お宝について何か知っているんですか？","ENG":"An Artifact...? Do you know something about this treasure?","TWN":"人造神器……？那你知道關於它的秘密嗎？"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"글쎄요? 부사장님이 중요한 물건이라 말씀하시긴 했는데.","JPN":"さあ？　副社長が重要品目であるとは言っていましたが。","ENG":"Not really. The Vice President did mention that it was something important.","TWN":"這個嘛？副總說是很重要的東西。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"솔직히 잘 모르겠네요. 켕기는 게 워낙 한두 가지여야지.","JPN":"正直なところ、よくわかっていません。色々と気になる要素があるので。","ENG":"But honestly, I'm not sure. There are a lot of suspicious things going on.","TWN":"實話說，我也不太清楚。可疑的地方太多了。"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"위험한 물건은 나도 알 수 있는걸!","JPN":"危険なものなら、私だってわかるよ！","ENG":"I can tell if something is dangerous, though!","TWN":"危險的東西我也能看出來！"},"stage":{"bg":"SUMMER_HOTEL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};